def verify(answer) -> bool:
    def f(x):
        return x**4 + 5*x**3 + 9*x**2 - x - 14

    # Parse answer into a list of integers (allowing commas and spaces)
    try:
        s = str(answer).strip()
        parts = [] if s == "" else [p.strip() for p in s.split(",")]
        cand_list = []
        for p in parts:
            if p == "":
                continue
            cand_list.append(int(p))
    except Exception:
        return False

    cand_set = set(cand_list)

    # All possible integer (rational) roots must divide the constant term 14
    const = 14
    poss = set()
    for d in range(1, abs(const) + 1):
        if const % d == 0:
            poss.add(d)
            poss.add(-d)

    true_roots = set([r for r in poss if f(r) == 0])

    # Check that provided roots are actual roots and that none are missing
    # Ignore order and duplicates
    for r in cand_set:
        if f(r) != 0:
            return False

    return cand_set == true_roots

