def verify(answer) -> bool:
    # Count all ways to select distinct president, vice-president, treasurer from 20 members
    count = 0
    n = 20
    for pres in range(n):
        for vp in range(n):
            if vp == pres:
                continue
            for treas in range(n):
                if treas == pres or treas == vp:
                    continue
                count += 1
    try:
