def verify(answer) -> bool:
    # Compute expected area from given coordinates: center (3,1) and point (8,1)
    dx, dy = 8 - 3, 1 - 1
    r2 = dx*dx + dy*dy  # squared radius = 25
    expected = r2 * pi  # area = 25*pi

    s = str(answer).strip()
    expr = None

    # Try integer first
    try:
        expr = Integer(int(s))
    except Exception:
        pass

    if expr is None:
        # Try sympy expression, allowing unicode pi
        try:
            s2 = s.replace('π', 'pi')
            expr = sympify(s2, {"pi": pi})
        except Exception:
            # Fallback: try float
            try:
                val = float(s)
                expv = float(expected.evalf())
                return abs(val - expv) <= 1e-6 * max(1.0, abs(expv))
            except Exception:
                return False

    try:
        if simplify(expr - expected) == 0:
            return True
        # Allow numerical approximation
        val = float(expr.evalf())
        expv = float(expected.evalf())
        return abs(val - expv) <= 1e-6 * max(1.0, abs(expv))
    except Exception:
        return False

