def verify(answer) -> bool:
    try:
        cand = int(str(answer).strip())
    except Exception:
        return False

    n = 28
    # Compute exact counts from fractions, ensuring divisibility
    if (n * 3) % 4 != 0 or (n * 6) % 7 != 0:
        return False
    brown = (n * 3) // 4
    right = (n * 6) // 7

    min_intersection = None
    for x in range(0, n + 1):  # x = number both
        y = brown - x          # brown only
        z = right - x          # right only
        w = n - (x + y + z)    # neither
        if y >= 0 and z >= 0 and w >= 0:
            if min_intersection is None or x < min_intersection:
                min_intersection = x

    if min_intersection is None:
        return False
    return cand == min_intersection

