    def parse_pair(ans):
        # If it's already a pair-like
        if isinstance(ans, (list, tuple)) and len(ans) == 2:
            try:
                x = int(str(ans[0]).strip())
                y = int(str(ans[1]).strip())
                return (x, y)
            except Exception:
                return None
        # Fallback: parse from string
        try:
            s = str(ans).strip()
            if s.startswith(("(", "[", "{")) and s.endswith((")", "]", "}")):
                s = s[1:-1].strip()
            if "," in s:
                parts = [p.strip() for p in s.split(",")]
            else:
                parts = s.split()
            if len(parts) != 2:
                return None
            x = int(parts[0])
            y = int(parts[1])
            return (x, y)
        except Exception:
            return None

    expected = (3, -4)
    cand = parse_pair(answer)
    return cand == expected

