from sympy import *
import math

def verify(answer) -> bool:
    x = Symbol('x')
    p = x**4 + 2*x**3 - 7*x**2 - 8*x + 12

    # Parse answer as comma-separated list (allow optional brackets)
    try:
        s = str(answer).strip()
        if s.startswith('[') and s.endswith(']'):
            s = s[1:-1]
        tokens = [t.strip() for t in s.split(',') if t.strip() != '']
        if len(tokens) != 4:
            return False
        cand_syms = []
        for t in tokens:
            cand_syms.append(sympify(t))
    except Exception:
        return False

    # Convert candidates to complex numbers with decent precision
    def to_cplx(z):
        try:
            return complex(N(z, 40))
        except Exception:
            return None

    cand_vals = [to_cplx(z) for z in cand_syms]
    if any(v is None for v in cand_vals):
        return False

    # Check each candidate is a root numerically
    for z in cand_syms:
        try:
            val = N(p.subs(x, z), 40)
            if abs(complex(val)) > 1e-8:
                return False
        except Exception:
            return False

    # Compute true roots numerically (with multiplicities)
    try:
        true_roots = [complex(r) for r in nroots(p, n=4)]
    except Exception:
        return False

    # Multiset match within tolerance
    tol = 1e-6
    remaining = true_roots[:]
    for c in cand_vals:
        found = False
        for i, t in enumerate(remaining):
            if abs(c - t) < tol:
                remaining.pop(i)
                found = True
                break
        if not found:
            return False

    return len(remaining) == 0

