def verify(answer) -> bool:
    # Verify the horizontal asymptote y-value for y = (27x^2+9x+3)/(27x^3+9x^2+3x+1)
    # We numerically test the limit as x -> ±infinity.
    def parse_number(a):
        s = str(a).strip()
        try:
            return float(s)
        except Exception:
            try:
                return float(int(s))
            except Exception:
                return None

    y_ans = parse_number(answer)
    if y_ans is None or math.isnan(y_ans) or math.isinf(y_ans):
        return False

    def f(x):
        num = 27*x*x + 9*x + 3
        den = 27*x**3 + 9*x**2 + 3*x + 1
        return num / den

    xs = [10**k for k in range(1, 7)]
    xs += [-x for x in xs]
    max_err = 0.0
    for x in xs:
        try:
            val = f(x)
        except ZeroDivisionError:
            return False
        err = abs(val - y_ans)
        if err > max_err:
            max_err = err

    return max_err < 1e-6

from sympy import symbols, simplify

def verify(answer) -> bool:
    try:
        ans = str(answer).strip().lower()
    except Exception:
        return False
    if ans not in {"odd", "even", "neither"}:
        return False
    x = symbols('x')
    f = 7*x**7 - 4*x**4 + 1
    is_even = simplify(f.subs(x, -x) - f) == 0
    is_odd = simplify(f.subs(x, -x) + f) == 0
    correct = "neither"
    if is_even and not is_odd:
        correct = "even"
    elif is_odd and not is_even:
        correct = "odd"
    return ans == correct

