    v = (2, 3, -1)
    w = (2, -1, 0)
    num = v[0]*w[0] + v[1]*w[1] + v[2]*w[2]  # v·w = 1
    den = w[0]*w[0] + w[1]*w[1] + w[2]*w[2]  # w·w = 5
    # Expected projection vector
    from sympy import Rational
    expected = (Rational(num, den)*w[0], Rational(num, den)*w[1], Rational(num, den)*w[2])

    # Per instructions: try to parse as int first; if succeeds, it's not correct (vector expected)
    try:
        _ = int(str(answer).strip())
        return False
    except Exception:
        pass

    def to_nums(obj):
        # Convert various representations to a length-3 tuple of numbers
        if isinstance(obj, (list, tuple)) and len(obj) == 3:
            return obj
        if isinstance(obj, str):
            s = obj.strip()
            for ch in '()[]{}':
                s = s.replace(ch, '')
            parts = [p for p in s.replace(',', ' ').split() if p]
            if len(parts) != 3:
                return None
            return parts
        return None

    arr = None
    if isinstance(answer, (list, tuple, str)):
        arr = to_nums(answer)
    elif hasattr(answer, '__iter__'):
        try:
            lst = list(answer)
            if len(lst) == 3:
                arr = lst
        except Exception:
            arr = None

    if arr is None:
        return False

    # Parse components to Rational if possible, else float
    parsed = []
    for x in arr:
        try:
            # Try exact rational parsing
            xs = str(x).strip()
            if '/' in xs:
                nume, deno = xs.split('/')
                parsed.append(Rational(int(nume), int(deno)))
            else:
                parsed.append(Rational(xs))
        except Exception:
            try:
                parsed.append(float(x))
            except Exception:
                return False

    # Compare with tolerance for floats
    tol = 1e-9
    for got, exp in zip(parsed, expected):
