        t2 = 149.0 - 140.0*math.sqrt(u)
        if t2 < 0:
            return float('inf')
        return math.sqrt(t1) + math.sqrt(t2)

    # Coarse grid search to locate a good starting point
    N = 20001
    a, b = -1.0, 1.0
    best_x, best_val = None, float('inf')
    step = (b - a) / (N - 1)
    x = a
    for _ in range(N):
        val = f(x)
        if val < best_val:
            best_val = val
            best_x = x
        x += step

    # Local ternary search around best_x
    left = max(a, best_x - 0.1)
    right = min(b, best_x + 0.1)
