    memo = {}
    def E(i, j, k, o):
        # i,j,k,o = counts seen so far of A,K,Q,Others
        if i > 0 and j > 0 and k > 0:
            return Fraction(0, 1)
        key = (i, j, k, o)
        if key in memo:
            return memo[key]
        n = 54 - (i + j + k + o)
        if n == 0:
            # Shouldn't happen unless already done
            return Fraction(0, 1)
        a = 4 - i
        b = 4 - j
        c = 4 - k
        d = 42 - o
        res = Fraction(1, 1)
        if a > 0:
            res += Fraction(a, n) * E(i + 1, j, k, o)
        if b > 0:
            res += Fraction(b, n) * E(i, j + 1, k, o)
        if c > 0:
            res += Fraction(c, n) * E(i, j, k + 1, o)
        if d > 0:
            res += Fraction(d, n) * E(i, j, k, o + 1)
        memo[key] = res
        return res

    expected = E(0, 0, 0, 0)

    s = str(answer).strip()
    # Try robust parsing: fraction, integer, or decimal
    parsed = None
    try:
        if '/' in s:
            parsed = Fraction(s)
        else:
