            parsed = Fraction(s)
    except Exception:
        try:
            parsed = Fraction(int(s), 1)
        except Exception:
            try:
                fv = float(s)
                return abs(fv - (expected.numerator / expected.denominator)) < 1e-9
            except Exception:
                return False

