    # Vertices are on a 4x4 grid: (x,y) with x,y in 0..3
    def count_configs():
        count = 0
        # Iterate over all 2^(3*3) configurations
        for mask in range(1 << 9):
            # Graph as adjacency set for vertices (x,y)
            adj = {}
            def add_edge(a, b):
                adj.setdefault(a, set()).add(b)
                adj.setdefault(b, set()).add(a)
            # For each cell decide diagonal
            for cy in range(3):
                for cx in range(3):
                    idx = cy * 3 + cx
                    bit = (mask >> idx) & 1
                    if bit == 0:
                        # backslash: (cx,cy) to (cx+1,cy+1)
                        a = (cx, cy)
                        b = (cx+1, cy+1)
                    else:
                        # slash: (cx,cy+1) to (cx+1,cy)
                        a = (cx, cy+1)
                        b = (cx+1, cy)
                    add_edge(a, b)
            # BFS from bottom-left (0,0) to top-right (3,3)
            start = (0, 0)
            target = (3, 3)
            if start not in adj or target not in adj:
                continue
            q = deque([start])
            seen = {start}
            found = False
            while q:
                u = q.popleft()
                if u == target:
                    found = True
                    break
                for v in adj.get(u, []):
                    if v not in seen:
                        seen.add(v)
                        q.append(v)
            if found:
                count += 1
        return count

    try:
        ans = int(str(answer).strip())
    except Exception:
        return False

    actual = count_configs()
    return ans == actual

