def verify(answer):
    mod = 13

    def alpha(n):
        if n == 0:
            return 0
        if n % 2 == 1:
            return n + 1
        else:
            return n - 1

    def inv_mod(x, m):
        x %= m
        if x == 0:
            return None
        # Extended Euclidean Algorithm
        a, b = x, m
        u0, u1 = 1, 0
        while b:
            q = a // b
            a, b = b, a - q * b
            u0, u1 = u1, u0 - q * u1
        return u0 % m

    def solve_mod(M, b, m):
        n = len(M)
        A = [row[:] + [b[i] % m] for i, row in enumerate(M)]
        row = 0
        for col in range(n):
            piv = None
            for r in range(row, n):
                if A[r][col] % m != 0:
                    piv = r
                    break
            if piv is None:
                continue
            A[row], A[piv] = A[piv], A[row]
            inv = inv_mod(A[row][col], m)
            if inv is None:
                return None
            for c in range(col, n + 1):
                A[row][c] = (A[row][c] * inv) % m
            for r in range(n):
                if r != row and A[r][col] % m != 0:
                    factor = A[r][col] % m
                    for c in range(col, n + 1):
                        A[r][c] = (A[r][c] - factor * A[row][c]) % m
            row += 1
            if row == n:
                break
        x = [A[i][n] % m for i in range(n)]
        return x

    # Build Vandermonde matrix and y values
    N = 13
    M = []
    y = []
    for n in range(N):
