    if coeffs is None:
        return False
    coeffs = [c % mod for c in coeffs]

    # Determine degree and coefficients
    d = 0
    for i in range(len(coeffs) - 1, -1, -1):
        if coeffs[i] != 0:
            d = i
            break
    a_d = coeffs[d] if d < len(coeffs) else 0
    a_1 = coeffs[1] if len(coeffs) > 1 else 0

    result = 100 * a_d + a_1
    try:
