    for _ in range(max_iter):
        next_a = (5.0 * a + math.sqrt(21.0 * a * a + 4.0)) / 2.0
        term = 1.0 / (a * next_a)
        total += term
        if term < 1e-15:
            break
        a = next_a
    else:
        # Did not converge fast enough
        return False

    return abs(cand - total) < 1e-9

from sympy import *
import math
from itertools import product

def verify(answer):
    try:
        ans = int(str(answer).strip())
    except Exception:
        return False

    R, C = 4, 6
    def idx(r,c): return r*C + c
    cells = [idx(r,c) for r in range(R) for c in range(C)]

    # Generate all L-triomino placements (3 cells in a 2x2 block)
    placements = []
    for r in range(R-1):
        for c in range(C-1):
            block = [idx(r,c), idx(r+1,c), idx(r,c+1), idx(r+1,c+1)]
            for miss in range(4):
                tri = tuple(sorted([block[i] for i in range(4) if i != miss]))
                placements.append(frozenset(tri))
    placements = list(dict.fromkeys(placements))  # unique (should already be unique)

    # For each cell, placements that cover it
    plc_by_cell = {u: [] for u in cells}
    for i,p in enumerate(placements):
        for u in p:
            plc_by_cell[u].append(i)

    # Exact cover search to enumerate tilings
    tilings = []
    def search(used, covered):
        if len(covered) == R*C:
            tilings.append(tuple(used))
            return
        # choose smallest uncovered cell
        for u in cells:
            if u not in covered:
                first = u
                break
        for pi in plc_by_cell[first]:
            p = placements[pi]
            if not p.isdisjoint(covered):
                continue
            used.append(pi)
            search(used, covered | p)
            used.pop()
    search([], frozenset())

    # Precompute side neighbors for cells
    nbrs = {}
    for r in range(R):
        for c in range(C):
            i = idx(r,c)
            ns = []
            if r>0: ns.append(idx(r-1,c))
            if r<R-1: ns.append(idx(r+1,c))
            if c>0: ns.append(idx(r,c-1))
            if c<C-1: ns.append(idx(r,c+1))
            nbrs[i] = ns

    # For each tiling, build adjacency graph among its 8 pieces and count 3-colorings
    def count_colorings(adj):
        n = len(adj)
        order = sorted(range(n), key=lambda v: -len(adj[v]))
        color = [-1]*n
        def dfs(i):
            if i==n: return 1
            v = order[i]
            used = {color[u] for u in adj[v] if color[u]!=-1}
            cnt = 0
            for col in range(3):
                if col not in used:
                    color[v]=col
                    cnt += dfs(i+1)
            color[v]=-1
            return cnt
        return dfs(0)

    total = 0
    for t in tilings:
        pieces = [placements[i] for i in t]
        cell2piece = {}
        for k,p in enumerate(pieces):
            for u in p: cell2piece[u]=k
        adj = [set() for _ in range(len(pieces))]
        for u in cells:
            pu = cell2piece[u]
            for v in nbrs[u]:
                pv = cell2piece[v]
                if pu != pv:
                    adj[pu].add(pv)
                    adj[pv].add(pu)
        total += count_colorings(adj)

    return ans == total
